UPDATE t_p31606708_tech_buying_service.catalog SET description='Samsung Galaxy S25 Ultra с встроенным S Pen, камерой 200 Мп и Snapdragon 8 Elite. Galaxy AI.', specs='{"Процессор":"Snapdragon 8 Elite","ОЗУ":"12 ГБ","Экран":"6.9 QHD+ AMOLED 120Гц","Камера":"200+50+10 Мп","S Pen":"встроен","5G":"да","Батарея":"5000 мАч"}' WHERE category='Samsung S-Z' AND model ILIKE '%S25 Ultra%';
UPDATE t_p31606708_tech_buying_service.catalog SET description='Samsung Galaxy S25+ — флагман с Snapdragon 8 Elite, Galaxy AI и экраном 6.7.', specs='{"Процессор":"Snapdragon 8 Elite","ОЗУ":"12 ГБ","Экран":"6.7 FHD+ AMOLED 120Гц","Камера":"50+10+12 Мп","5G":"да","Батарея":"4900 мАч"}' WHERE category='Samsung S-Z' AND (model ILIKE '%S25+%' OR model ILIKE '%S25 Plus%');
UPDATE t_p31606708_tech_buying_service.catalog SET description='Samsung Galaxy S25 — компактный флагман с Galaxy AI и Snapdragon 8 Elite.', specs='{"Процессор":"Snapdragon 8 Elite","ОЗУ":"12 ГБ","Экран":"6.2 FHD+ AMOLED 120Гц","Камера":"50+12+10 Мп","5G":"да","Батарея":"4000 мАч"}' WHERE category='Samsung S-Z' AND model ILIKE '%S25%' AND model NOT ILIKE '%Ultra%' AND model NOT ILIKE '%+%' AND model NOT ILIKE '%Plus%';
