UPDATE t_p31606708_tech_buying_service.catalog SET description='iPad 11 с A16 Bionic, дисплеем Liquid Retina 11 и поддержкой Apple Pencil Pro.', specs='{"Чип":"Apple A16 Bionic","Дисплей":"11 Liquid Retina","Разъём":"USB-C","Apple Pencil":"Pro","Wi-Fi":"6E"}' WHERE category='Apple iPad' AND model ILIKE '%iPad 11%';
